package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds
import kotlin.time.Duration.Companion.microseconds
import kotlin.time.Duration.Companion.seconds

class ToDelayMillisTest {

    @Test
    fun testZeroDuration() {
        assertEquals(0, Duration.ZERO.toDelayMillis())
    }

    @Test
    fun testNegativeDuration() {
        assertEquals(0, (-1).milliseconds.toDelayMillis())
        assertEquals(0, (-1).seconds.toDelayMillis())
        assertEquals(0, (-1).nanoseconds.toDelayMillis())
    }

    @Test
    fun testSubMillisecondDurationsRoundUp() {
        // Any positive sub-millisecond duration should round up to 1ms
        assertEquals(1, 1.nanoseconds.toDelayMillis())
        assertEquals(1, 500.nanoseconds.toDelayMillis())
        assertEquals(1, 999999.nanoseconds.toDelayMillis())
        assertEquals(1, 1.microseconds.toDelayMillis())
        assertEquals(1, 500.microseconds.toDelayMillis())
        assertEquals(1, 999.microseconds.toDelayMillis())
    }

    @Test
    fun testExactMilliseconds() {
        // Exact milliseconds should not be rounded
        assertEquals(1, 1.milliseconds.toDelayMillis())
        assertEquals(2, 2.milliseconds.toDelayMillis())
        assertEquals(1000, 1.seconds.toDelayMillis())
    }

    @Test
    fun testMillisecondsWithSubMillisPart() {
        // Durations with sub-millisecond parts should round up
        // 998ms + 902752ns = 998.902752ms -> should round up to 999ms
        assertEquals(999, (998.milliseconds + 902752.nanoseconds).toDelayMillis())

        // 1ms + 1ns = 1.000001ms -> should round up to 2ms
        assertEquals(2, (1.milliseconds + 1.nanoseconds).toDelayMillis())

        // 1ms + 500us = 1.5ms -> should round up to 2ms
        assertEquals(2, (1.milliseconds + 500.microseconds).toDelayMillis())

        // 1ms + 999999ns = 1.999999ms -> should round up to 2ms
        assertEquals(2, (1.milliseconds + 999999.nanoseconds).toDelayMillis())
    }

    @Test
    fun testInfiniteDuration() {
        // Duration.INFINITE should return Long.MAX_VALUE
        assertEquals(Long.MAX_VALUE, Duration.INFINITE.toDelayMillis())
    }

    @Test
    fun testLargeDurations() {
        // Large durations (but not infinite) should still work correctly
        val largeDuration = Long.MAX_VALUE.milliseconds
        assertEquals(Long.MAX_VALUE, largeDuration.toDelayMillis())
    }

    @Test
    fun testIssueReproducer() {
        // Reproducer from issue: 998ms + 902752ns should delay for 999ms (rounded up)
        // not 998ms (truncated)
        val expectedDuration = 998.milliseconds + 902752.nanoseconds
        val delayMillis = expectedDuration.toDelayMillis()

        // The bug was that this would return 998 (truncating the nanoseconds)
        // The fix ensures it returns 999 (rounding up)
        assertTrue(delayMillis >= 999, "Expected at least 999ms, but got $delayMillis")
    }
}
"}

